import machine
import usocket as socket
from microcoapy import CoAP, Resource, RequestHandler

# Set up the device's network interface
wlan = machine.WLAN(machine.AIOWIFI)
wlan.active(True)

# Create a CoAP server instance
server = CoAP()

# Define resources for temperature sensor and light actuator
class SensorTemp(Resource):
    def render_get(self, request):
        # Simulate temperature reading from sensor
        temp = 25.0
        return b'{"temperature": %f}' % temp

class ActuatorLight(Resource):
    def render_put(self, request):
        # Set the light state based on the PUT request payload
        if 'on' in request.payload:
            machine.Pin(2, machine.Pin.OUT).value(1)
        else:
            machine.Pin(2, machine.Pin.OUT).value(0)

# Add resources to the CoAP server
server.add_resource('/sensors/temp', SensorTemp())
server.add_resource('/actuators/light', ActuatorLight())

# Set up a secure connection using DTLS (Datagram Transport Layer Security)
context = socket.create_connection(('localhost', 5684))
server.bind((('0.0.0.0', 5683), context))

# Start the CoAP server
print("CoAP Server started on port 5683")
try:
    while True:
        request, client_address = server.accept()
        if request is not None:
            handler = RequestHandler(request)
            response = handler.handle_request()
            print(f"Received request from {client_address}: {request.method} {request.uri}")
            server.send_response(response, client_address)
except KeyboardInterrupt:
    pass
finally:
    server.close()